from flask import Flask, request, jsonify
import os
import json
import time
import hashlib

app = Flask(__name__)
CACHE_DIR = 'cache'
CACHE_EXPIRATION = 300  # seconds

if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def get_cache_key(url, params):
    key = url + json.dumps(params, sort_keys=True)
    return hashlib.md5(key.encode()).hexdigest()

def load_from_cache(cache_key):
    cache_file = os.path.join(CACHE_DIR, cache_key + '.json')
    if os.path.exists(cache_file):
        with open(cache_file, 'r') as f:
            data = json.load(f)
            if time.time() - data['timestamp'] < CACHE_EXPIRATION:
                return data['response']
    return None

def save_to_cache(cache_key, response):
    cache_file = os.path.join(CACHE_DIR, cache_key + '.json')
    data = {
        'timestamp': time.time(),
        'response': response
    }
    with open(cache_file, 'w') as f:
        json.dump(data, f)

@app.route('/api/data', methods=['GET'])
def get_data():
    url = request.url
    params = request.args.to_dict()
    cache_key = get_cache_key(url, params)
    
    cached_response = load_from_cache(cache_key)
    if cached_response:
        return jsonify(cached_response)
    
    # Simulate an expensive API call
    response = {
        'data': 'Expensive API response',
        'metadata': {'source': 'API'}
    }
    
